def gen(rng, size):
    word = ''.join(rng.choice('abc') for _ in range(rng.randint(1, 100)))
    m = rng.randint(1, min(100, max(1, size)))
    pats = []
    for _ in range(m):
        if rng.random() < 0.5 and len(word) > 0:
            i = rng.randrange(len(word))
            j = rng.randint(i + 1, len(word))
            pats.append(word[i:j])
        else:
            pats.append(''.join(rng.choice('abcd') for _ in range(rng.randint(1, 5))))
    return [pats, word]

