class Solution:
    def numOfStrings(self, patterns, word):
        count = 0
        for p in patterns:
            found = False
            for i in range(len(word) - len(p) + 1):
                if word[i:i+len(p)] == p:
                    found = True
                    break
            if found:
                count += 1
        return count

solutions.python:
class Solution:
    def numOfStrings(self, patterns, word):
        return sum(1 for p in patterns if p in word)

